import json

MAX_INPUT_SIZE = 256

def process_user_input(request_payload):
    """Process user input safely with length validation."""
    try:
        data = json.loads(request_payload)
        user_input = data.get("input", "")
        request_id = data.get("request_id")

        # Validate input size to prevent buffer overflow
        if len(user_input) > MAX_INPUT_SIZE:
            return {"status": "error", "message": "Input too large"}

        # Process the validated input
        result = f"Processed: {user_input}"

        return {"status": "success", "result": result}
    except Exception as e:
        return {"status": "error", "message": str(e)}
